// project/plugins.sbt
addSbtPlugin("software.purpledragon" % "sbt-dependency-lock"  % "1.4.1")
addSbtPlugin("com.timushev.sbt"      % "sbt-updates"          % "0.6.4")
addSbtPlugin("org.owasp"             % "sbt-dependency-check" % "9.0.7")

// build.sbt — pin exact versions; never use dynamic ranges
libraryDependencies ++= Seq(
  "org.typelevel" %% "cats-core" % "2.10.0",
  "co.fs2"        %% "fs2-core"  % "3.10.0",
  "org.http4s"    %% "http4s-dsl"% "0.23.27"
)

// sbt dependencyLockWrite   → generate/update build.sbt.lock
// sbt dependencyLockCheck   → CI gate: fails on drift
// sbt dependencyUpdates     → list available upstream upgrades
// sbt dependencyCheck       → OWASP NVD CVE report

// build.sbt
enablePlugins(JmhPlugin)

import org.openjdk.jmh.annotations._
import java.util.concurrent.TimeUnit

@State(Scope.Thread)
@BenchmarkMode(Array(Mode.AverageTime))
@OutputTimeUnit(TimeUnit.NANOSECONDS)
@Warmup(iterations = 5, time = 1)
@Measurement(iterations = 10, time = 1)
@Fork(2)
class ListVsArrayBench {
  val list: List[Int] = (1 to 1000).toList
  val arr: Array[Int] = (1 to 1000).toArray

  @Benchmark def sumList(): Int = list.sum       // boxes each Int
  @Benchmark def sumArray(): Int = arr.sum       // stays unboxed
}

// sbt build.sbt — wire up remote debugging + Bloop export
lazy val root = project.in(file("."))
  .settings(
    scalaVersion := "3.4.1",
    fork := true,
    javaOptions ++= Seq(
      "-agentlib:jdwp=transport=dt_socket,server=y,suspend=n,address=5005"
    )
  )

// Then in shell:
// sbt bloopInstall          <- generates .bloop/ config
// bloop compile root        <- fast incremental compile
// bloop console root        <- REPL with full classpath

// application.conf — isolate blocking I/O from actor dispatcher
blocking-io-dispatcher {
  type = Dispatcher
  executor = "thread-pool-executor"
  thread-pool-executor {
    fixed-pool-size = 32
  }
  throughput = 1
}

// Inside an actor — offload blocking work
val blockingDispatcher = context.system.dispatchers.lookup("blocking-io-dispatcher")
Future {
  // JDBC / blocking HTTP call here
  database.query("SELECT ...")
}(blockingDispatcher).pipeTo(self)
